import json

class CustomObject:
    def __init__(self, value):
        self.value = value

def save_preferences(filename, preferences):
    with open(filename, 'w') as file:
        json.dump(preferences, file, default=lambda o: o.__dict__, indent=4)

def load_preferences(filename):
    with open(filename, 'r') as file:
        preferences = json.load(file)
        # Convert custom objects back
        for key, value in preferences.items():
            if isinstance(value, dict) and '__class__' in value:
                class_name = value.pop('__class__')
                module_name = value.pop('module')
                obj_class = globals()[class_name]
                preferences[key] = obj_class(**value)
        return preferences